+    let stats = pt_core::collect::parse_statm(std::process::id())?;
+    let page_size = unsafe { libc::sysconf(libc::_SC_PAGESIZE) };
+    if page_size <= 0 {
+        return None;
+    }
+    let rss_bytes = stats.resident.saturating_mul(page_size as u64);
+    Some(rss_bytes / 1024 / 1024)
